import { Component, effect, inject, ViewChild } from "@angular/core";
import { WithDestroy } from "./WithDestroy";
import { DxButtonModule, DxDataGridComponent, DxDataGridModule, DxSwitchModule } from "devextreme-angular";
import { exportDataGrid } from "devextreme/excel_exporter";
import { Workbook } from "exceljs";
import { saveAs } from 'file-saver';
import { ThemeService } from "@app/services/theme.service";
import { firstValueFrom, lastValueFrom, Observable, take, takeUntil } from "rxjs";
import { ApiService } from "@services/api.service";
import notify from "devextreme/ui/notify";
import { Globals } from "@app/services/globals.service";
import { EditMode } from "@app/models/enum";




@Component({
    template: '',
    standalone:true,
    imports: [DxSwitchModule, DxButtonModule, DxDataGridModule]
  })

export class BaseGrid<T> extends WithDestroy() {
@ViewChild('gridContainer', {static: false}) gridx: DxDataGridComponent;
private themeService = inject(ThemeService);
protected api = inject(ApiService);
protected globals = inject(Globals);


editMode = EditMode.Read
rowIndex = -1;
rowFilter = false;
columnLines = false;
subTotals = false;
headerFilter = false;
pagingEnabled = true;
expanded = true;
hoverIndex = -1;
focusedRowIndex = -1;
colorMode='';
themeclass = 'dark-theme';
defaultBaanAdministration = '';
networkLocation:string;
recordIdField:string;
editInline = true;
page = 1;
pageSize = 25;

public info = ' ';
public showclearFilterSwitch=true;
public showColumnLinesSwitch=true;
public showHeaderFilterSwitch=true;
public showRowFilterSwitch=true;
public showGridCaption=false;
public showAddButton = false;
public showRefreshButton  = true;
public showSubTotalsSwitch = false;
public showTreeButton = false;
public showInlineEditButton = false;
public addButtonLocation='after';
public refreshButtonLocation='after';
public showColumnChooserButton = false;
public showMultiSelect = false;
public multiSelect = false;
public selectionMode = "single"

headerfilterText='header filter';
rowfilterText = 'row filter';
clearFilterText = 'clear filter';
columnLinesText = 'column lines';

editingRowIndex = -1; 

// Delete support
dialogVisible = false;
deleteTarget: { id: number; name: string } | null = null;
entityName = 'record';
entityEndpoint = 'entities';

// Save support
record!: T & { id?: number };
loading = false;
records: T[] = [];
validationMessage = '';
popupVisible = false;

@ViewChild('formRef') formRef: any;

euroformat = { style: 'currency',  currency: 'EUR', useGrouping: true, minimumIntegerDigits:1 ,minimumFractionDigits: 4, maximumFractionDigits:4 };
euroformat2 = { style: 'currency',  currency: 'EUR', useGrouping: true, minimumIntegerDigits:1 ,minimumFractionDigits: 2, maximumFractionDigits:2 };
fixedformat = { type:'fixedPoint', useGrouping: true, precision: 4};
fixedformat2 = { type:'fixedPoint', useGrouping: true, precision: 2};
fixedformat0 = { type:'fixedPoint', useGrouping: true, precision: 0};
private storageKey = '';

constructor() {
    super();
    this.themeService.currentTheme$
    .pipe(takeUntil(this.destroy$))
      .subscribe(theme => {
        if(theme === 'light'){
          this.themeclass='light-theme';
        } else {
          this.themeclass='dark-theme';
        }
      });
      
    effect(() => {
      try {
        const s = this.globals.settings();
          if (!s) return; // not loaded yet
          this.defaultBaanAdministration = s.defaultBaanAdministration ?? '';
          
        } catch (err) {
          console.error('BaseGrid effect error:', err);
        }
      }); 
    }

    onToolbarPreparing(e:any) {
      e.toolbarOptions.items.unshift(
        {
          location: 'before',
          template: 'headercaption',
          visible: this.showGridCaption
        },
        {
          location: 'before',
          widget: 'dxButton',
          cssClass: 'informer',
          visible: this.showTreeButton,
          options: {
                    icon: 'mdi mdi-expand-all',
                    stylingMode: 'text',
                    onClick: this.expandAll.bind(this),
                    visible: true
                  }
        },
        {
          location: 'after',
          text: "multiselect",
          widget: 'dxSwitch',
          cssClass: 'informer infcheckbox',
          visible: this.showMultiSelect,
          options: {
            value: this.multiSelect,
            onValueChanged: this.ShowMultiSelect.bind(this),
            hint: 'show multiSelect',
            visible: this.showMultiSelect,
          }
        },         
        {
          location: 'after',
          text: "subtotals",
          widget: 'dxSwitch',
          cssClass: 'informer infcheckbox',
          visible: this.showSubTotalsSwitch,
          options: {
            value: this.subTotals,
            onValueChanged: this.ShowSubtotals.bind(this),
            hint: 'show subtotals',
            visible: this.showSubTotalsSwitch
          }
        },
       
        {
          location: 'after',
          text: "inline edit",
          widget: 'dxSwitch',
          cssClass: 'informer infcheckbox',
          visible: this.showInlineEditButton,
          options: {
            value: this.editInline,
            onValueChanged: this.setInlineEdit.bind(this),
            hint: 'inline edit',
            visible: this.showInlineEditButton
          }
        },        
        {
          location: 'after',
          text: this.columnLinesText,
          widget: 'dxSwitch',
          cssClass: 'informer infcheckbox',
          visible: this.showColumnLinesSwitch,
          options: {
            value: this.columnLines,
            onValueChanged: this.ShowColumnLines.bind(this),
            hint: 'column lines',
            visible: this.showColumnLinesSwitch
          }
        },
        {
          location: 'after',
          text: this.headerfilterText,
          widget: 'dxSwitch',
          cssClass: 'informer infcheckbox',
          visible: this.showHeaderFilterSwitch,
          options: {
            value: this.headerFilter,
            onValueChanged: this.ShowHeaderFilter.bind(this),
            hint: 'header filters',
            visible: this.showHeaderFilterSwitch
          }
        },
        {
          location: 'after',
          text: this.rowfilterText,
          widget: 'dxSwitch',
          cssClass: 'informer infcheckbox',
          visible:  this.showRowFilterSwitch,
          options: {
            value: this.rowFilter,
            onValueChanged: this.ShowRowFilter.bind(this),
            hint: 'row filters',
            visible: this.showRowFilterSwitch
          }
        },
        {
          location: 'after',
          text: this.clearFilterText,
          
          widget: 'dxButton',
          cssClass: 'informer infcheckbox',
          visible: this.showclearFilterSwitch,
          options: {
                    icon: 'mdi mdi-filter-remove-outline',
                    stylingMode: 'text',
                    onClick: this.clearFilterA.bind(this),
                    hint: 'reset filters',
                    visible: this.showclearFilterSwitch
                  }
        },
        {
          location: this.addButtonLocation,
          widget: 'dxButton',
          cssClass: 'informer',
          visible: this.showAddButton,
          options: {
                    icon: 'add',
                    stylingMode: 'outline',
                    type:'default',
                    onClick: this.addRecord.bind(this),
                    hint: 'add new record',
                    visible: this.showAddButton
                  }
        },
        {
          location: this.refreshButtonLocation,
          widget: 'dxButton',
          cssClass: 'informer',
          visible: this.showRefreshButton,
          options: {
                    icon: 'refresh',
                    stylingMode: 'outline',
                    type:'default',
                    onClick: this.refresh.bind(this),
                    hint: 'reload data',
                    visible: this.showRefreshButton
                  }
        } ,  
        {
          location: 'after',
          text: "",
          widget: 'dxButton',
          cssClass: 'informer infcheckbox',
          visible: this.showColumnChooserButton,
          options: {
            icon: 'mdi mdi-reorder-vertical',
            stylingMode: 'outline',
            type:'default',
            onClick: this.ShowColumnChooser.bind(this),
            hint: 'show column chooser',
            visible: this.showColumnChooserButton
          }
        }, 
        );
    }

  saveColumnLayout(): void {
    if (this.gridx?.instance && this.storageKey) {
      try {
        const state = this.gridx.instance.state();
        localStorage.setItem(`grid-state-${this.storageKey}`, JSON.stringify(state));
      } catch (error) {
        console.error('Failed to save grid state:', error);
      }
    }
  }

  loadColumnLayout(): void {
    if (!this.gridx?.instance || !this.storageKey) {
      //console.log('Cannot load - gridx or storageKey missing:', !!this.gridx?.instance, this.storageKey);
      return;
    }

    const savedState = localStorage.getItem(`grid-state-${this.storageKey}`);
    if (!savedState) {
      //console.log('No saved state found for:', this.storageKey);
      return;
    }

    try {
      const state = JSON.parse(savedState);
      //console.log('Loading grid state for:', this.storageKey, state);
      
      // Check if grid is ready before applying state
      if (this.gridx.instance.getDataSource() && this.gridx.instance.getDataSource().isLoaded()) {
        this.gridx.instance.beginUpdate();
        
        try {
          this.gridx.instance.state(state);
          this.gridx.instance.endUpdate();
          //console.log('State applied successfully');
        } catch (stateError) {
          console.error('Failed to apply grid state, clearing saved state:', stateError);
          localStorage.removeItem(`grid-state-${this.storageKey}`);
          this.gridx.instance.endUpdate();
          
          this.gridx.instance.refresh();
        }
      } else {
        // If data source is not loaded yet, wait a bit more
        setTimeout(() => {
          this.loadColumnLayout();
        }, 200);
      }
    } catch (error) {

      localStorage.removeItem(`grid-state-${this.storageKey}`);
    }
  }

    setStorageKey(key: string): void {
      this.storageKey = key;
  }

    public setInlineEdit(e: any) {
      this.editInline = e.value;
      // if (this.editInline) {
      //   this.gridx.instance.option('editing.mode', 'row');
      // } 
    }

    public ShowColumnChooser(e: any) {
      if (this.gridx?.instance) {
        this.gridx.instance.showColumnChooser();  
      }
    }   
    public addRecord(e: any){

    }

    afterSave(): void {
      // Hook for child components to override
    }
    
    public refresh(e:any) {
      
    }

    onCellHoverChanged  (e:any)  {
      if(e.rowType==="data"){
        this.hoverIndex = e.rowIndex;
      } else {
        this.hoverIndex = -1;
      }
    }
    
    getRowIndex(data: { rowType: string; key: any; }): number {
      if (data.rowType==="data"){
        this.rowIndex = this.gridx.instance.getRowIndexByKey(data.key);
        return this.rowIndex;}
      else
        return 0;
    }

    /* 
    Laad data vanuit rechstreekse json array
    */
    loadDataDirect(spParams?: Map<string, string>): void {
      this.loading = true;
      this.records = [];
      this.api.get<T[]>(`${this.entityEndpoint}`,spParams)
        .pipe(take(1))
        .subscribe({
          next: (result) => {
            console.log('basegrid ==> loadDataDirect', result);
            this.records = result;
            this.loading = false;
          },
          error: (err) => {
            console.error(`basegrid: loadData: Error loading ${this.entityName} records`, err);
            this.loading = false;
          }
        });
    }

    loadDataFromUrl(url:string,spParams?: Map<string, string>): void {
      this.loading = true;
      this.records = [];
      this.api.get<T[]>(url,spParams)
        .pipe(take(1))
        .subscribe({
          next: (result) => {
            this.records = result;
            console.log('basegrid ==> loadDataFromUrl', result);
            this.loading = false;
          },
          error: (err) => {
            console.error(`basegrid: loadData: Error loading ${this.entityName} records`, err);
            this.loading = false;
          }
        });
    }

    rowUpdating (e: any) {
      const updated = { ...e.oldData, ...e.newData };
      const result = firstValueFrom(this.api.put<T>(`${this.entityEndpoint}/${updated.id}`, updated));

      e.cancel = new Promise<boolean>((resolve, reject) => {
        result.then((result) => {
          resolve(false);
          e.newData = result;
          this.editMode = EditMode.Read;
        })
          .catch((err) => {
            console.error('basegrid rowUpdating Update failed', err);
            reject(err?.message || 'Unknown error');
            this.editMode = EditMode.Read;
          });
      })
    }
 

  rowInserting= (e: any) => {
    const insertRecord= <T>{};
    const inserted = { ...insertRecord, ...e.data };
    //console.log('basegrid ==> procname', inserted);
    const result = firstValueFrom(this.api.post<T>(`${this.entityEndpoint}`, inserted))

    e.cancel = new Promise<boolean>((resolve, reject) => {
      result.then((result) => {
        console.log('basegrid ==> rowInserting', result);
        resolve(false);
        e.data=result;
        this.editMode = EditMode.Read;
      })
        .catch((err) => {
          console.error('basegrid Inserting failed', err);
          reject(err?.message || 'Unknown error');
          this.editMode = EditMode.Read;
        });
    })
  }

 rowRemoving = (e: any) => {
    const id = e.key;
    const result = firstValueFrom(this.api.delete(`${this.entityEndpoint}/${id}`));
    e.cancel = new Promise<boolean>((resolve, reject) => {
      result.then((result) => {
        resolve(false)
        this.editMode = EditMode.Read;
        
      })
        .catch((err) => {
          console.error('basegrid Deleting failed', err);
          reject(err?.message || 'Unknown error');
          this.editMode = EditMode.Read;
        });
    })
  }

    //Toolbar switches ==================================================================
    ShowColumnLines = (e:any) => {
      this.columnLines = e.value;
      this.gridx.instance.option('showColumnLines', e.value);
   }

    clearFilterA= () => {
      this.gridx.instance.clearFilter();
    }
  
    ShowSubtotals = (e:any) => {
      this.subTotals = e.value;
    }

    ShowMultiSelect = (value: boolean) => {
      this.multiSelect = value;
      
      if (this.multiSelect) {
        this.selectionMode = "multiple";
      } else {
        this.selectionMode = "single";
      }
      this.gridx.instance.option('selection.mode', this.selectionMode);
      this.gridx.instance.repaint();
    }
    ShowHeaderFilter= (e:any) => {
      this.headerFilter=e.value;
      this.gridx.instance.option('headerFilter.visible', e.value);
    }
  
    ShowRowFilter = (e:any) => {
      this.rowFilter=e.value;
      this.gridx.instance.option('filterRow.visible', e.value);
    }
  
    set showExportButton(e: boolean) {
      this.gridx.instance.option('export.enabled',e);
    }
    showSearchPanel(e: boolean) {
      this.gridx.instance.option('searchPanel.visible',e);
    }
    showGroupPanel(e: boolean) {
      this.gridx.instance.option('groupPanel.visible',e);
    }

    expandAll(){
      this.expanded = !this.expanded;
      if (this.expanded) {
        this.gridx.instance.expandAll();
      }
      if (!this.expanded) {
        this.gridx.instance.collapseAll();
      }
    }  

    //events=============================================================================
    onExporting(e: any, sheetName:string) {
      const workbook = new Workbook();
      const worksheet = workbook.addWorksheet(sheetName);
  
    exportDataGrid({
          component: e.component,
          worksheet,
          autoFilterEnabled: true,
        }).then(() => {
          workbook.xlsx.writeBuffer().then((buffer) => {
            saveAs(new Blob([buffer], { type: 'application/octet-stream' }), sheetName+'.xlsx');
          });
        });
        e.cancel = true;
    }



}

import { HttpErrorResponse, HttpInterceptorFn } from '@angular/common/http';
import { inject } from '@angular/core';
import { Router } from '@angular/router';
import { catchError, tap, throwError, of } from 'rxjs';

import { Globals } from '@app/services/globals.service';
import { ErrorService } from '@app/services/error.service';


/**
 * Guards to avoid repeated navigation / spam
 */
let navigatedToServerDown = false;

const formatValidationErrors = (payload: unknown): string | null => {
  if (!payload || typeof payload !== 'object') {
    return null;
  }

  const errors = (payload as { errors?: Record<string, unknown> }).errors;
  if (!errors || typeof errors !== 'object') {
    return null;
  }

  const details: string[] = [];

  for (const [field, value] of Object.entries(errors)) {
    if (Array.isArray(value)) {
      details.push(`${field}: ${value.join(', ')}`);
    } else if (value !== null && value !== undefined) {
      details.push(`${field}: ${String(value)}`);
    }
  }

  return details.length > 0 ? details.join('\n') : null;
};

export const globalErrorInterceptor: HttpInterceptorFn = (req, next) => {
  const router        = inject(Router);
  const globals       = inject(Globals);
  const errorService  = inject(ErrorService);


  return next(req).pipe(

    /**
     * Any successful response means the server is reachable again
     */
    tap({
      next: () => {
        if (!globals.serverAvailable()) {
          globals.setServerAvailable(true);
          navigatedToServerDown = false;

          if (router.url.startsWith('/error/server-down')) {
            router.navigateByUrl('/');
          }
        }
      }
    }),

    /**
     * Centralized error handling
     */
    catchError((err: HttpErrorResponse) => {

      //console.log('global-error.interceptor.ts ==> err', err);

      let title = 'Request failed';
      let message = 'An unexpected error occurred.';
      let postAction: (() => void) | null = null;

      // status === 0 means: no HTTP response (network/CORS/abort)
      // NEVER log out on this

      

      if (err.status === 0) {
        globals.setServerAvailable(false);

        errorService.show({
          title: 'Server not reachable',
          message: `No response received from backend.\n\n${err.url ?? ''}`,
          severity: 'error',
          status: 0,
          autoDismissMs: undefined
        });

        return throwError(() => err);
      }

      /**
       * Unauthorized
       */

      else if (err.status === 401) {
        console.log('global-error.interceptor ==> procname 401', err);
        const msg = (err.error as any)?.message ?? err.message;
        title = 'Authentication failed';
        message = `${msg} Please check your credentials and try again.`;
      }

      /**
       * Forbidden
       */
      else if (err.status === 403) {
        console.log('global-error.interceptor ==> procname 403', err);
        title = 'Access denied';
        message = 'You do not have permission to perform this action.';
        postAction = () => router.navigateByUrl('/');
      }

      /**
       * Not found 404
       */
      else if (err.status === 404) {
        console.log('global-error.interceptor ==> procname 404', err);
        title = 'Not found';
        const url =
          (err.error as any)?.instance ||
          err.url ||
          'Unknown endpoint';

        message = `The requested endpoint was not found:\n${url}`;
        console.log('global-error.interceptor ==> message:', message);
      }
      /**
       * Not found 405
       */
      else if (err.status === 405) {
        console.log('global-error.interceptor ==> procname 405', err);
        title = 'Method not allowed';

        const method = err.headers?.get('Allow')
          ? `Allowed: ${err.headers.get('Allow')}`
          : '';

        const url = err.url ?? 'Unknown endpoint';

        message =
          `The endpoint exists but does not support this HTTP method.\n\n` +
          `${url}\n${method}`;
      }
      else if (err.status === 409) {
        console.log('global-error.interceptor ==> procname 409',err);
        title =
          (err.error as any)?.title ??
          'Invalid operation';

        message =
          (err.error as any)?.detail ??
          err.message ??
          'The requested operation is not allowed in the current state.';
      }

      /**
       * Validation / bad request
       */
      else if (err.status === 400 || err.status === 422) {
        console.log('global-error.interceptor ==> procname 400', err);
        const payload = err.error;
        title = (payload as any)?.title ?? 'Validation failed';

        if (typeof payload === 'string') {
          message = payload;
        } else if (payload && typeof payload === 'object') {
          const baseMessage =
            (payload as any)?.detail ??
            (payload as any)?.message ??
            'One or more validation errors occurred.';

          const validationDetails = formatValidationErrors(payload);
          message = validationDetails ? `${baseMessage}\n${validationDetails}` : baseMessage;
        } else {
          message = 'One or more validation errors occurred.';
        }
      }

      /**
       * Server-side errors
       */
      else if (err.status >= 500) {
        console.log('global-error.interceptor ==> procname', err.status);
        title = (err.error as any)?.title ?? 'Server error';
        message =
          (err.error as any)?.detail ??
          'The server encountered an error. Please try again later.';
      }

      /**
       * 🔴 SINGLE UX HANDOFF (no dialogs, no alerts)
       */
      let severity: 'info' | 'warning' | 'error';

      if (err.status === 0 || err.status >= 500) {
        severity = 'error';
      }
      else if (err.status === 400 || err.status === 404 || err.status === 422) {
        severity = 'warning';
      }
      else {
        severity = 'info';
      }


      errorService.show({
        title,
        message,
        severity,
        status: err.status,
        instance: (err.error as any)?.instance,

        autoDismissMs:
          severity === 'info' ? 5000 :
          severity === 'warning' ? 7000 :
          undefined   // errors stay until user closes
      });

      if (postAction) {
        postAction();
      }

      return throwError(() => err);
    })
  );
};

import { Component, effect, EventEmitter, inject, Input, Output } from '@angular/core';

import { DxSwitchModule, DxButtonModule } from 'devextreme-angular';
import { signal } from '@angular/core';
import { takeUntil } from 'rxjs';
import { Globals } from '@app/services/globals.service';
import { WithDestroy } from '@app/helpers/WithDestroy';
import { ThemeService } from '@app/services/theme.service';
import { AuthStateService } from '@app/services/auth-state.service';


@Component({
  selector: 'app-footer',
  standalone: true,
  imports: [DxSwitchModule, DxButtonModule],
  templateUrl: './footer.html',
  styleUrls: ['./footer.scss']
})
export class Footer extends WithDestroy() {
  currentYear = new Date().getFullYear();
  private themeService = inject(ThemeService)
  private globals = inject(Globals);
  auth = inject(AuthStateService);
  username = signal<string | null>(null);
  administratie = "test";
  themeValue = true; // true for dark theme, false for light theme
  baseUrl='';
  version = '';

  constructor() {
    super();

    this.themeService.currentTheme$
      .pipe(takeUntil(this.destroy$))
      .subscribe(t => {
        this.themeValue = t === 'dark';
      });

    effect(() => {
    const s = this.globals.settings();   // IAppConfig | null
    if (s) {
      this.administratie = s.defaultBaanAdministration;
      this.version = s.version;
    }

    const url = this.globals.apiBaseUrl(); // already trimmed & no trailing slash
    if (url) {
      this.baseUrl = url;
    }
    });
  }


  themeChange(value: boolean) {
    this.themeService.switchTheme(value);
  }

}

import { CommonModule } from '@angular/common';
import { AfterViewInit, Component, OnInit } from '@angular/core';
import { AmsLoadPanelComponent } from '@app/helpers/ams-load-panel/ams-load-panel.component';
import { BaseGrid } from '@app/helpers/basegrid';
import { EditMode } from '@app/models/enum';
import { FinishDto, FinishPaintLayerDto, FinishPaintDto, FinishPaintSystemDto, ManufacturerDto } from '@app/models/finish.model';
import { FinishesAdd } from '@app/pages/basedata/finishes-add/finishes-add';
import { DxButtonModule, DxDataGridModule, DxFormModule, DxPopupModule, DxSelectBoxModule, DxToolbarModule } from 'devextreme-angular';
import { confirm } from 'devextreme/ui/dialog';
import notify from 'devextreme/ui/notify';
import { firstValueFrom } from 'rxjs';

interface RawPaintLayerRecipe {
  id?: number;
  finishCode?: string;
  paintLine?: string;
  customer?: string;
  customerNumber?: string;
  substrate?: string;
  surfaceTreatment?: string;
  surfaceQuality?: string;
  preTreatment?: string;
  runs?: number;
  side?: string;
  maxSpeedRun1?: number;
  maxSpeedRun2?: number;
  maxSpeedRun3?: number;
  state?: string;
  version?: string;
  paintLayers?: RawPaintLayer[];
}

interface RawPaintLayer {
  id?: number;
  layerNumber?: number;
  side?: string;
  paintCode?: string;
  paintDescription?: string;
  layerThickness?: number;
  paintSystem?: string;
  manufacturer?: string;
  metallicType?: string;
  nonWhite?: boolean;
  aluNatur?: boolean;
  volumeFractionOfSolid?: number;
  isPrimer?: boolean;
  isWrinkle?: boolean;
