    this.api.get<CampaignDto[]>(`production-orders/campaigns`, spParams).subscribe({
      next: (numbers) => {
        console.log('production ==> getCampaignNumbersForSelectedProdLine', numbers);
        this.campaignNumbers = (numbers ?? []).map((c) => ({
          ...c,
